# =============================================================================
# Logging Function
# =============================================================================

def log(msg):
    """Write to both log file and console."""
    with open(LOG_FILE, 'a', encoding='utf-8') as f:
        f.write(f"{msg}\n")
        f.flush()  # Critical for real-time monitoring
    print(msg, flush=True)  # -u flag compatibility

# =============================================================================
# Main Analysis
# =============================================================================

if __name__ == "__main__":
    try:
        log("[START] Step 03: merge_analysis_dataset")

        # =========================================================================
        # STEP 1: Load Input Data
        # =========================================================================
        # Expected: RAVLT forgetting scores from Step 01, REMEMVR slopes from Step 02
        # Purpose: Combine both datasets for correlation analysis

        log("[LOAD] Loading input datasets...")

        # Load RAVLT scores (Step 01 output)
        ravlt_path = RQ_DIR / "data" / "step01_ravlt_scores.csv"
        ravlt_df = pd.read_csv(ravlt_path, encoding='utf-8')
        log(f"[LOADED] RAVLT scores: {len(ravlt_df)} rows, {len(ravlt_df.columns)} cols")
        log(f"[INFO] RAVLT columns: {ravlt_df.columns.tolist()}")

        # Load REMEMVR slopes (Step 02 output)
        slopes_path = RQ_DIR / "data" / "step02_rememvr_slopes.csv"
        slopes_df = pd.read_csv(slopes_path, encoding='utf-8')
        log(f"[LOADED] REMEMVR slopes: {len(slopes_df)} rows, {len(slopes_df.columns)} cols")
        log(f"[INFO] REMEMVR columns: {slopes_df.columns.tolist()}")

        # =========================================================================
        # STEP 2: Merge Datasets
        # =========================================================================
        # Tool: pandas.merge (inner join)
        # What it does: Combine datasets on UID, keep only participants with both datasets
        # Expected output: N=100 merged dataset (should be no data loss)

        log("[ANALYSIS] Merging datasets on UID...")

        # Inner join to ensure both RAVLT and slope data present
        merged_df = pd.merge(ravlt_df, slopes_df, on='UID', how='inner')

        log(f"[MERGE] Input 1 (RAVLT): {len(ravlt_df)} rows")
        log(f"[MERGE] Input 2 (Slopes): {len(slopes_df)} rows")
        log(f"[MERGE] Output (Merged): {len(merged_df)} rows")

        # Check for data loss
        if len(merged_df) < len(ravlt_df) or len(merged_df) < len(slopes_df):
            missing_from_ravlt = len(ravlt_df) - len(merged_df)
            missing_from_slopes = len(slopes_df) - len(merged_df)
            log(f"[WARNING] Data loss detected:")
            log(f"  - Missing from RAVLT: {missing_from_ravlt} participants")
            log(f"  - Missing from Slopes: {missing_from_slopes} participants")
        else:
            log("[PASS] No data loss - all participants retained")

        # Report merged dataset statistics
        log(f"[INFO] Merged dataset columns: {merged_df.columns.tolist()}")
        log(f"[STATS] RAVLT_Forgetting - Mean: {merged_df['RAVLT_Forgetting'].mean():.3f}, SD: {merged_df['RAVLT_Forgetting'].std():.3f}")
        if 'RAVLT_Pct_Ret' in merged_df.columns:
            log(f"[STATS] RAVLT_Pct_Ret - Mean: {merged_df['RAVLT_Pct_Ret'].mean():.3f}, SD: {merged_df['RAVLT_Pct_Ret'].std():.3f}")
        log(f"[STATS] REMEMVR_Slope - Mean: {merged_df['REMEMVR_Slope'].mean():.4f}, SD: {merged_df['REMEMVR_Slope'].std():.4f}")

        # =========================================================================
        # STEP 3: Save Merged Dataset
        # =========================================================================
        # This output will be used by: Steps 04-08 (correlation analyses)

        log(f"[SAVE] Saving merged dataset...")
        output_path = RQ_DIR / "data" / "step03_analysis_input.csv"
        merged_df.to_csv(output_path, index=False, encoding='utf-8')
        log(f"[SAVED] {output_path} ({len(merged_df)} rows, {len(merged_df.columns)} cols)")

        # =========================================================================
        # STEP 4: Run Validation Tool
        # =========================================================================
        # Tool: validate_data_columns
        # Validates: Required columns present for correlation analysis
        # Required columns: UID, RAVLT_Forgetting, REMEMVR_Slope

        log("[VALIDATION] Running validate_data_columns...")

        required_columns = ["UID", "RAVLT_Forgetting", "REMEMVR_Slope"]

        validation_result = validate_data_columns(
            df=merged_df,
            required_columns=required_columns
        )

        # Report validation results
        if isinstance(validation_result, dict):
            for key, value in validation_result.items():
                log(f"[VALIDATION] {key}: {value}")

            if validation_result.get('valid', False):
                log("[VALIDATION] PASS - All required columns present")
            else:
                log("[VALIDATION] FAIL - Missing required columns")
                log(f"[VALIDATION] Missing: {validation_result.get('missing_columns', [])}")
        else:
            log(f"[VALIDATION] {validation_result}")

        log("[SUCCESS] Step 03 complete")
        sys.exit(0)

    except Exception as e:
        log(f"[ERROR] {str(e)}")
        log("[TRACEBACK] Full error details:")
        with open(LOG_FILE, 'a', encoding='utf-8') as f:
            traceback.print_exc(file=f)
        traceback.print_exc()
        sys.exit(1)
